from collections import deque
class Solution:
    def makeStringGood(self, s):
        freq = [0] * 26
        for ch in s:
            freq[ord(ch) - 97] += 1
        start = tuple(freq)
        cap = len(s) + 2
        def is_good(state):
            nz = [c for c in state if c > 0]
            return len(set(nz)) <= 1
        if is_good(start):
            return 0
        dist = {start: 0}
        q = deque([start])
        while q:
            cur = q.popleft()
            d = dist[cur]
            for i in range(26):
                if cur[i] > 0:
                    nxt = list(cur)
                    nxt[i] -= 1
                    t = tuple(nxt)
                    if t not in dist:
                        dist[t] = d + 1
                        if is_good(t):
                            return d + 1
                        q.append(t)
                if cur[i] < cap:
                    nxt = list(cur)
                    nxt[i] += 1
                    t = tuple(nxt)
                    if t not in dist:
                        dist[t] = d + 1
                        if is_good(t):
                            return d + 1
                        q.append(t)
                if i < 25 and cur[i] > 0:
                    nxt = list(cur)
                    nxt[i] -= 1
                    nxt[i + 1] += 1
                    t = tuple(nxt)
                    if t not in dist:
                        dist[t] = d + 1
                        if is_good(t):
                            return d + 1
                        q.append(t)
        return -1

