var makeStringGood = function(s) {
    const n = s.length;
    const freq = new Array(26).fill(0);
    for (const ch of s) freq[ch.charCodeAt(0) - 97]++;
    const maxf = Math.max(...freq);
    let best = n;
    for (let T = 1; T <= maxf; T++) {
        let dp0 = freq[0];
        let dp1 = Math.abs(freq[0] - T);
        for (let i = 1; i < 26; i++) {
            const avail0 = freq[i - 1];
            const avail1 = Math.max(0, freq[i - 1] - T);
            const deficit = Math.max(0, T - freq[i]);
            const isolated0 = freq[i];
            const isolated1 = Math.abs(freq[i] - T);
            const ndp0 = Math.min(dp0, dp1) + isolated0;
            const ndp1 = Math.min(
                dp0 + (isolated1 - Math.min(avail0, deficit)),
                dp1 + (isolated1 - Math.min(avail1, deficit))
            );
            dp0 = ndp0; dp1 = ndp1;
        }
        best = Math.min(best, dp0, dp1);
    }
    return best;
};
